const item = $input.first().json;
item.t_analyze = Date.now();
return { json: item };

return {
  json: {
    text: `:white_check_mark: *${$('Parse Alert').item.json.alertname}* on ${$('Parse Alert').item.json.service} looks auto-resolved — no failing pods on last check.`
  }
};

const ragAnswer = $('Mark RAG Latency').first().json.answer;
const ragSources = $('Mark RAG Latency').first().json.sources.join(', ');
const failingPods = $('Mark Failing Pods Latency').first().json.failing_pods;
const recentEvents = $('Mark Events Latency').first().json.recent_events;

const failingPodsText = failingPods.length > 0
  ? failingPods.map(p => `• ${p.name} (${p.phase})`).join('\n')
  : 'None currently failing';

return {
  json: {
    text: `*${$('Parse Alert').item.json.alertname}* — ${$('Parse Alert').item.json.service} (${$('Parse Alert').item.json.namespace})\n\n` +
          `*Runbook guidance:*\n${ragAnswer}\n_Source: ${ragSources}_\n\n` +
          `*Current cluster state:*\n${failingPodsText}\n\n` +
          `*Recent events:* ${recentEvents.length} events in last check\n\n` +
          `*Analysis:* ${$('Analyze (Vertex AI)').item.json.text || $('Analyze (Vertex AI)').item.json.output}`
  }
};

const t_parsed = $('Parse Alert').item.json.t_parsed;
const t_rag = $('Mark RAG Latency').item.json.t_rag;
const t_pods = $('Mark Failing Pods Latency').item.json.t_pods;
const t_events = $('Mark Events Latency').item.json.t_events;
const t_analyze = $('Mark Analyze Latency').item.json.t_analyze;
const t_now = Date.now();

return {
  json: {
    timestamp: new Date().toISOString(),
    alertname: $('Parse Alert').item.json.alertname,
    namespace: $('Parse Alert').item.json.namespace,
    auto_resolved: $('Mark Failing Pods Latency').item.json.failing_pods.length === 0,
    workflow_execution_id: $execution.id,
    latency_ms: {
      rag_query: t_rag - t_parsed,
      mcp_failing_pods: t_pods - t_parsed,
      mcp_events: t_events - t_parsed,
      llm_analysis: t_analyze - Math.max(t_rag, t_pods, t_events),
      total: t_now - t_parsed
    }
  }
};
